let events = [];
const allItems = $input.all();

if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
    events = allItems[0].json;
} else if (allItems.length === 1 && allItems[0].json.data && Array.isArray(allItems[0].json.data)) {
    events = allItems[0].json.data;
} else {
    events = allItems.map(item => item.json);
}

// 接收外部传参，如果没有就用默认值
let rawInput = "stock, s&p, nasdaq, nvda, bitcoin, crypto, crude oil, gold， rate cut, inflation, cpi, fed, boj, ecb, war, tariff, china, stimulus, copper, natural gas, sliver"; 
const keywords = rawInput.toLowerCase().split(',').map(k => k.trim()).filter(k => k !== "");

const blackList = [
    'knights', 'golden', 'nhl', 'nba', 'nfl', 'mlb', 'soccer', 'league', 
    'world cup', 'olympic', 'match', 'esports', 'vs.', 'warriors', 'lakers'
];

let filteredEvents = events.filter(e => {
    if (!e.title) return false;
    const lowerTitle = e.title.toLowerCase();

    // 💡 新增：把 Description 也转成小写拉进来检查
    const lowerDesc = (e.description || "").toLowerCase();

    // 1. 黑名单大扫荡：不仅查标题，连描述里的蛛丝马迹也不放过！
    if (blackList.some(badWord => lowerTitle.includes(badWord) || lowerDesc.includes(badWord))) {
        return false; 
    }

    // 2. 通过了黑名单的，才去匹配我们的宏观关键词
    return keywords.some(kw => lowerTitle.includes(kw));
});

function formatMoney(amount) {
    let val = parseFloat(amount || 0);
    if (val >= 1000000) return `$${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `$${(val / 1000).toFixed(0)}k`;
    return `$${val.toFixed(0)}`;
}

let finalTrending = [];

for (let e of filteredEvents) {
    if (!e.markets || e.markets.length === 0) continue;

    let mainMarket = e.markets[0]; 
    let prices = mainMarket.outcomePrices;

    if (typeof prices === 'string') {
        try { prices = JSON.parse(prices); } catch(err) { prices = []; }
    }

    if (!Array.isArray(prices) || prices.length < 2) continue;

    let yPrice = parseFloat(prices[0]);
    let nPrice = parseFloat(prices[1]);

    if (yPrice >= 0.95 || yPrice <= 0.05) continue; 

    let yesOdds = (yPrice * 100).toFixed(1) + "%";
    let noOdds = (nPrice * 100).toFixed(1) + "%";

    let imageUrl = e.image || mainMarket.icon || "https://polymarket.com/favicon.ico";
    let liqAmount = parseFloat(e.liquidity || mainMarket.liquidity || 0);
    let formattedLiquidity = formatMoney(liqAmount);

    // ✅ 新增：拼接 Polymarket 官方事件链接
    let eventUrl = `https://polymarket.com/event/${e.slug}`;

    finalTrending.push({
        "Event": e.title,
        "Specific_Question": mainMarket.question,
        "Volume": formatMoney(e.volume) + " Vol.",
        "Liquidity": formattedLiquidity + " Liq.",
        "Yes": yesOdds,
        "No": noOdds,
        "Event_URL": eventUrl, // <-- 以后直接推送到 Discord 的链接
        "Image_URL": imageUrl,  // <-- 以后用于 Discord 的缩略图
        "starte_date": e.startDate,
        "end_date": e.endDate
    });

    if (finalTrending.length >= 10) break;
}

return [{ json: { polymarket_trending: finalTrending } }];
